mapper.select:
select message_id, message_type, title, content, business_type, business_id, jump_target, read_status, receiver_user_id, receiver_user_name, event_time, create_by, create_time, update_by, update_time, remark from nc_business_message
del_flag = '0'
and receiver_user_name = #{receiverUserName}
and read_status = #{readStatus}
order by event_time desc, message_id desc

mapper.update:
update nc_business_message
set read_status = #{readStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}
where message_id = #{messageId}
  and del_flag = '0'
